var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"힉......?!","JPN":"ひッ……！？","ENG":"Hic...","TWN":"咿……？！"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"BATTLE_NORMAL_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"RYAN_PRYDWEN_NULL_NULL","text":{"KOREA":"빙벽만 세운다고 끝이 아닙니다.","JPN":"氷壁だけを建てたところで無駄ですよ。","ENG":"Having an ice wall up won't solve everything.","TWN":"不是只要豎起冰牆就好了。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"BATTLE_NORMAL_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RYAN_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"RYAN_PRYDWEN_NULL_NULL","text":{"KOREA":"동료를 지키고 싶다면 좀 더 전술적인 움직임을 고민하십시오.","JPN":"仲間を守りたければ、もっと戦術的な動きを考えるべきです。","ENG":"Try to be more strategic with your movement if you want to protect your allies.","TWN":"想要保護同伴的話，就請想想更有戰術性的行動吧。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"BATTLE_NORMAL_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RYAN_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"저, 적에게 갑자기 왜 충고를 해 주는 거죠?","JPN":"ど、どうして敵にアドバイスするんですか？","ENG":"W-what are you giving me advice for? I'm your enemy!","TWN":"你、你突然給敵人忠告幹嘛？"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"BATTLE_NORMAL_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"RYAN_PRYDWEN_NULL_NULL","text":{"KOREA":"그런 건 중요하지 않습니다. 정정당당한 승부야말로 지켜야 할 가치니까요.","JPN":"そんなことはどうでもいいんですよ。正々堂々とした勝負こそが守るべき価値あるものですから。","ENG":"It doesn't matter. Fairness in a fight is a virtue worthy of pursuit.","TWN":"這不重要。因為只有堂堂正正的對決才有守護的價值。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"BATTLE_NORMAL_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RYAN_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"RIVET_ESPR_NULL_NULL","text":{"KOREA":"에델, 조심해!","JPN":"エデル、気を付けて！","ENG":"Watch out, Edel!","TWN":"艾瑟兒，小心！"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"BATTLE_NORMAL_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RIVET_ESPR_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"THADDEUS_PRYDWEN_NULL_NULL","text":{"KOREA":"흐음, 신임 학회장이라더니 정말 만만치 않군.","JPN":"ふむ、新任の学会長はさすがに手ごわいな。","ENG":"The new President of the Society is a real handful.","TWN":"哼嗯，不愧是新任學會長，果然不簡單啊。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"BATTLE_NORMAL_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"THADDEUS_PRYDWEN_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"THADDEUS_PRYDWEN_NULL_NULL","text":{"KOREA":"이래서야 접근하기 어렵겠는데.","JPN":"これじゃあ近寄ることもできないぞ。","ENG":"We won't be able to approach her this way.","TWN":"這樣下去很難接近呢。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"BATTLE_NORMAL_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"THADDEUS_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"ELIZABETH_PRYDWEN_NULL_NULL","text":{"KOREA":"그럼 제가 길을 열어 드리죠.","JPN":"ならば、私が道を開いて差し上げましょう。","ENG":"Then let me open the path.","TWN":"那就讓我來開路吧。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"BATTLE_NORMAL_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"THADDEUS_PRYDWEN_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"EDEL_ESPR_NULL_NULL","text":{"KOREA":"꺄악!!","JPN":"きゃーっ！！","ENG":"Urgh!","TWN":"呀啊！！"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EDEL_ESPR_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"ELIZABETH_PRYDWEN_NULL_NULL","text":{"KOREA":"실랑이는 우아하지 않으니까요.","JPN":"もみ合いは優雅ではありませんから。","ENG":"There's nothing elegant about a cat fight.","TWN":"紛爭可一點都不優雅。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"THEMA_PRYDWEN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_COMBAT_ALL_FOOT_STEP_LANDING_SMALL"},{"id":"L23_1","type":"dialog","speaker":"RYAN_PRYDWEN_NULL_NULL","text":{"KOREA":"아, 아가씨! 함선에 계시라고 몇 번이나 말씀 드렸지 않습니까!","JPN":"お、お嬢様！　艦船にいてくださいと何度も申し上げたはずです！","ENG":"L-Lady Elizabeth! I told you a thousand times, you must stay inside the ship!","TWN":"大、大小姐！不是說了好幾遍，請您待在艦船上了嗎！"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"THEMA_PRYDWEN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"THADDEUS_PRYDWEN_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"RYAN_PRYDWEN_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L24_1","type":"dialog","speaker":"THADDEUS_PRYDWEN_NULL_NULL","text":{"KOREA":"자네 아직도 포기 안 했나?","JPN":"君はまだ諦めてなかったのか？","ENG":"Just let it go, will you?","TWN":"你還沒有放棄啊？"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"THEMA_PRYDWEN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"THADDEUS_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RYAN_PRYDWEN_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L25_1","type":"dialog","speaker":"THADDEUS_PRYDWEN_NULL_NULL","text":{"KOREA":"내 친구지만 고집 한 번 대단하군.","JPN":"我が友ながら、意固地な奴だ。","ENG":"I must say, you're one stubborn fella.","TWN":"雖然是我的朋友，但你還真不是一般的固執啊。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"THEMA_PRYDWEN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"THADDEUS_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RYAN_PRYDWEN_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L27_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"저 사람은......?","JPN":"あの人は……？","ENG":"Who is she?","TWN":"那個人是……？"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"THEMA_PRYDWEN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"ELIZABETH_PRYDWEN_NULL_NULL","text":{"KOREA":"프리드웬 기관장, 엘리자베스 팬드래건이랍니다.","JPN":"プリドウェン機関長、エリザベス・ペンドラゴンと申します。","ENG":"I'm Elizabeth Pendragon, chief of the Prydwen Institution.","TWN":"我是普利多溫機關機關長，伊莉莎白·潘德拉貢。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"THEMA_PRYDWEN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"ELIZABETH_PRYDWEN_NULL_NULL","text":{"KOREA":"보고를 통해 얘기는 들어 왔지만, 실제로 대면하긴 처음이군요.","JPN":"報告を通じて話は聞いておりましたが、実際に対面するのは初めてですわね。","ENG":"It's a pleasure to meet you in person, although I have read a lot about you.","TWN":"雖然在報告裡聽說過了，但實際面對面還是第一次呢。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"THEMA_PRYDWEN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"프리드웬 기관장......? 당신이?","JPN":"プリドウェン機関長……？　あなたが？","ENG":"You're the chief of Prydwen?","TWN":"普利多溫機關機關長……？妳？"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"THEMA_PRYDWEN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"RIVET_ESPR_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L33_1","type":"dialog","speaker":"RIVET_ESPR_NULL_NULL","text":{"KOREA":"그런 게 정말 있었네? 세상에 맙소사!","JPN":"本当に存在してたんだね！　ビックリしたー！","ENG":"Shiver me timbers, they really existed!","TWN":"還真的有那種東西啊？天啊！"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"THEMA_PRYDWEN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"RIVET_ESPR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L34_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"에델이 말할 때는 신나게 맞장구 치더니, 실제로 있는지도 몰랐던 거예요?!","JPN":"エデルが話してる時は一緒になって合わせてたくせに、実在すると思ってなかったんですか！？","ENG":"You didn't even know they existed? What were all those things you said to back Edel up then?","TWN":"艾瑟兒說的時候，妳不是附和得很開心嗎？結果自己都不知道它是不是真實存在啊！？"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"THEMA_PRYDWEN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"RIVET_ESPR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L35_1","type":"dialog","speaker":"RIVET_ESPR_NULL_NULL","text":{"KOREA":"노련한 용병은 의뢰주가 사슴을 말이라고 불러도 맞장구 쳐 주는 법!","JPN":"ベテラン傭兵はクライアントが鹿を馬だって言っても合わせてやるものなの！","ENG":"A skilled mercenary agrees with the client, even if she were to call a deer a horse.","TWN":"經驗豐富的傭兵，就算委託人指鹿為馬也會好好配合的！"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"THEMA_PRYDWEN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"RIVET_ESPR_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L36_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"용병이 아니라 그냥 간신배잖아요! 당신 정말 뭐 하는 작자야!","JPN":"傭兵じゃなくて、ただのイエスマンでしょう！　あなた、本当に何者なんですの！","ENG":"I bet you were just not that interested. You're unbelievable!","TWN":"什麼傭兵，那就只是奸臣而已吧！妳這傢伙到底是做什麼的啊！"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"THEMA_PRYDWEN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RIVET_ESPR_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L38_1","type":"dialog","speaker":"ELIZABETH_PRYDWEN_NULL_NULL","text":{"KOREA":"당신이 새로운 학회장, 그리고 당신이 돌아온 맥크레디 가문의 후계자로군요.","JPN":"あなたが新しい学会長、そしてこちらの方が帰ってきたマクレディー家の後継者なのですね。","ENG":"So you're the new President of the Society, and you, the heir of the MacCready family.","TWN":"妳是新任學會長，而妳則是回到故鄉的麥克蕾蒂家族繼承人啊。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"THEMA_PRYDWEN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"EDEL_ESPR_NULL_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"THEMA_PRYDWEN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"EDEL_ESPR_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L42_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"THEMA_PRYDWEN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"EDEL_ESPR_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L44_1","type":"dialog","speaker":"ELIZABETH_PRYDWEN_NULL_NULL","text":{"KOREA":"어째서 이번에는 그 둘이 나누어졌는지는 모르겠지만......","JPN":"どうして二人いるのかわかりませんが……","ENG":"I don't see how the one isn't the other this time, but...","TWN":"雖然不知道為什麼這次變成了兩個人，但是……"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"THEMA_PRYDWEN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"ELIZABETH_PRYDWEN_NULL_NULL","text":{"KOREA":"<color=#ffd34c>탐식자</color>를 봉인할 의무를 가진 자로서, 두 가지 선택지를 드리죠.","JPN":"<color=#ffd34c>貪食者</color>を封印する義務を持つ者として、二つの選択肢を提示しましょう。","ENG":"As someone obligated to seal the <color=#ffd34c>Devourer</color>, I'd like to offer you two options.","TWN":"身為負責封印<color=#ffd34c>貪食者</color>的義務者，我給你們兩個選擇。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"THEMA_PRYDWEN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"ELIZABETH_PRYDWEN_NULL_NULL","text":{"KOREA":"하나는 완전하고 즉각적인 항복이랍니다.","JPN":"一つは即刻かつ完全な降伏です。","ENG":"One: You surrender, immediately and completely.","TWN":"一是完全並立刻投降。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"THEMA_PRYDWEN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"ELIZABETH_PRYDWEN_NULL_NULL","text":{"KOREA":"세상 밖으로는 다시 나올 수 없겠지만, 격리구역 안에서의 안락한 여생을 약속해 드리겠어요.","JPN":"二度と世に出ることはできませんが、隔離区域内での穏やかな余生を約束しましょう。","ENG":"You won't be able to come out to the world, but I promise you comfortable life behind our fence.","TWN":"雖然可能再也無法到外面的世界去，但我保證你們可以在隔離區域內安度餘生。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"THEMA_PRYDWEN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"......다른 하나는 뭐죠?","JPN":"……もう一つは何ですの？","ENG":"And what's the other option we have?","TWN":"……另一個是什麼？"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"THEMA_PRYDWEN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"ELIZABETH_PRYDWEN_NULL_NULL","text":{"KOREA":"당연히 이곳에서 제 칼날 아래 스러지는 것이랍니다.","JPN":"もちろん、ここで私の刃の錆になることですわ。","ENG":"You fall under my knives, of course.","TWN":"當然，是在這裡倒在我的刀下。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"THEMA_PRYDWEN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"협박범 주제에 마치 선심이라도 쓰는 것 같군요.","JPN":"脅迫犯の分際で、慈悲を施すかのように言うのですね。","ENG":"Hah! You make a threat sound like a suggestion.","TWN":"明明就是脅迫，說得倒像是對我們大發慈悲一樣。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"THEMA_PRYDWEN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"다시 말씀드리지만, 전 맥크레디 영지의 정당한 주인으로서 당신들의 무단 침입과 파괴 행위에 대해 반드시 책임을 물을 겁니다!","JPN":"もう一度言いますが、私はマクレディー領地の正当な主です。\\nあなたたちには不法侵入と破壊行為の責任を取っていただきますわ！","ENG":"I'll say it again. As the rightful owner of the MacCready Estate, I'll hold you responsible for the intrusion and destruction you committed in this place!","TWN":"再說一次，身為麥克蕾蒂領地的正統所有人，我一定會追究你們的侵入和破壞行為！"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"THEMA_PRYDWEN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"ELIZABETH_PRYDWEN_NULL_NULL","text":{"KOREA":"좋습니다. 협상은 결렬이군요.","JPN":"いいでしょう。交渉は決裂ですわね。","ENG":"Fine. The deal's off then.","TWN":"很好。交涉決裂了呢。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"THEMA_PRYDWEN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"ELIZABETH_PRYDWEN_NULL_NULL","text":{"KOREA":"피차 조직을 이끌게 된 신예인 셈이니, 한 번쯤 자웅을 가려보는 것도 나쁘지 않겠죠.","JPN":"お互いに組織を率いることになった新鋭ですから、一度くらいは雌雄を決するのも悪くないでしょう。","ENG":"We both are the new leaders of our organizations. Maybe it's a good idea to find out who's better than whom.","TWN":"既然我們都是領導各自組織的新秀，那在這裡分個高下也不錯呢。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"THEMA_PRYDWEN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"ELIZABETH_PRYDWEN_NULL_NULL","text":{"KOREA":"아, 그 전에 먼저 한 가지 가르쳐 드리죠.","JPN":"ああ、その前に一つお教えしておきますわね。","ENG":"Ah, I'd like to tell you one thing before we start.","TWN":"啊，在這之前，先告訴你們一件事吧。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"THEMA_PRYDWEN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"ELIZABETH_PRYDWEN_NULL_NULL","text":{"KOREA":"전 체스로 빗대면 퀸, 보석으로 빗대면 알렉산드라이트랍니다.","JPN":"私はチェスで例えるならばクイーン、宝石で例えるならばアレキサンドライトです。","ENG":"I'd be a queen if I were a chess piece, and alexandrite if I were a gemstone.","TWN":"我在西洋棋中是皇后，在寶石中就是紫翠石。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"THEMA_PRYDWEN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"ELIZABETH_PRYDWEN_NULL_NULL","text":{"KOREA":"당신들에게 승산 따윈 없다는 사실을 잘 인지하고 덤비시길.","JPN":"あなた方に勝ち目など無いということを認知された上で、戦われますよう。","ENG":"Be aware that you stand no chance against me.","TWN":"希望你們認清自己毫無勝算的事實。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"THEMA_PRYDWEN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"......아니, 뭐 저런 여자가 다 있어?","JPN":"……何なんですの、あの人は。","ENG":"Is she being serious right now?","TWN":"……呃，會有女人像她這樣嗎？"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"THEMA_PRYDWEN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"RIVET_ESPR_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L10_1","type":"dialog","speaker":"RIVET_ESPR_NULL_NULL","text":{"KOREA":"와...... 부끄러움도 없이 저런 대사를 하다니, 과연 귀족 영애다워.","JPN":"わぁ……あんな台詞を恥ずかしげもなく言えるなんて、さすが貴族のお嬢様だね。","ENG":"Wow, just... Wow. She didn't even blink while saying those cheesy lines. Is everyone of noble birth like that?","TWN":"哇……能夠毫不害羞地說出這種台詞，真不愧是貴族的大小姐啊。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"THEMA_PRYDWEN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"RIVET_ESPR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L11_1","type":"dialog","speaker":"RIVET_ESPR_NULL_NULL","text":{"KOREA":"레지나도 처음 만났을 땐 비슷했던 것 같은데.","JPN":"レジーナも初めて会ったときはあんな感じだったけど。","ENG":"Come to think of it, she reminds me of you when we first met, Regina.","TWN":"第一次遇見蕾佳娜的時候，妳也跟她很像呢。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"THEMA_PRYDWEN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"RIVET_ESPR_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L12_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"저, 저 정도는 아니죠!!","JPN":"わ、私はあれほどではありませんわ！！","ENG":"I-I was never as bad as she is!","TWN":"我、我沒有到那個地步吧！！"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"THEMA_PRYDWEN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"RIVET_ESPR_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L13_1","type":"dialog","speaker":"RIVET_ESPR_NULL_NULL","text":{"KOREA":"......은근히 저렇게 보이길 기대하고 있었나 봐?","JPN":"……意外とあんな風に見てほしかったみたいだね。","ENG":"So you know you were like her to some extent.","TWN":"……原來妳暗自希望自己是那個樣子啊？"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"THEMA_PRYDWEN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"RIVET_ESPR_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L15_1","type":"dialog","speaker":"ELIZABETH_PRYDWEN_NULL_NULL","text":{"KOREA":"곧 티타임이네요.","JPN":"もうすぐティータイムですわね。","ENG":"It's getting near tea time.","TWN":"馬上就要到下午茶時間了呢。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"THEMA_PRYDWEN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"ELIZABETH_PRYDWEN_NULL_NULL","text":{"KOREA":"최대한 신속하게......","JPN":"できるだけ早く……","ENG":"I'll have to end this quickly","TWN":"我會盡可能迅速地……"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"THEMA_PRYDWEN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"ELIZABETH_PRYDWEN_NULL_NULL","text":{"KOREA":"실력의 차이를 느끼게 해 드리죠.","JPN":"実力の差を感じさせて差し上げましょう。","ENG":"and enjoy my cup of tea.","TWN":"讓你們感受到實力的差距。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"THEMA_PRYDWEN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}}]`);export{e as default};